induction C; (exists match C with
    | AtomF i => [i]
    | ContradictionF => []
    | NegationF C1 => proj1_sig IHC1
    | ConjunctionF C1 C2 => proj1_sig IHC1 ++ proj1_sig IHC2
    | DisjunctionF C1 C2 => proj1_sig IHC1 ++ proj1_sig IHC2
    | ImplicationF C1 C2 => proj1_sig IHC1 ++ proj1_sig IHC2
    | BiconditionalF C1 C2 => proj1_sig IHC1 ++ proj1_sig IHC2
    end); split;
  [ lazymatch C with
    | AtomF i => simpl; intuition
    | ContradictionF => simpl; intuition
    | NegationF C1 => destruct IHC1 as [ls1 [Hocc1 Hdec1]]; simpl; simpl in Hocc1; exact Hocc1
    | ConjunctionF C1 C2 | DisjunctionF C1 C2 | ImplicationF C1 C2 | BiconditionalF C1 C2 =>
      destruct IHC1 as [ls1 [Hocc1 Hdec1]]; destruct IHC2 as [ls2 [Hocc2 Hdec2]];
      simpl; simpl in Hocc1, Hocc2; split;
      [ intros l H; rewrite in_app_iff in H; destruct H as [H|H];
        [ apply Hocc1, H | apply Hocc2, H ]
      | intros [H|H]; rewrite in_app_iff;
        [ left; apply Hocc1, H | right; apply Hocc2, H ] ]
    end
  | lazymatch C with
    | AtomF i => intros e; simpl; destruct (e i); apply ByAssumption; simpl; auto
    | ContradictionF => intros e; simpl; apply NegationI; apply ByAssumption; simpl; auto
    | NegationF C1 =>
      destruct IHC1 as [ls1 [Hocc1 Hdec1]];
      intros e; simpl; destruct (eval_bool e C1) eqn:He;
      [ apply NegationI; eapply ContradictionI;
        [ eapply extend_infers; [ apply (Hdec1 e) | intros x Hx; unfold E.insert; simpl; right; exact Hx ]
        | apply ByAssumption; simpl; auto ]
      | apply (Hdec1 e) ]
    | ConjunctionF C1 C2 =>
      destruct IHC1 as [ls1 [Hocc1 Hdec1]]; destruct IHC2 as [ls2 [Hocc2 Hdec2]];
      intros e; simpl; destruct (eval_bool e C1) eqn:He1; destruct (eval_bool e C2) eqn:He2;
      [ eapply ConjunctionI;
        [ eapply extend_infers; [ apply (Hdec1 e) | intros x Hx; unfold E.fromList in Hx; simpl in Hx; unfold E.fromList; simpl; apply in_or_app; left; exact Hx ]
        | eapply extend_infers; [ apply (Hdec2 e) | intros x Hx; unfold E.fromList in Hx; simpl in Hx; unfold E.fromList; simpl; apply in_or_app; right; exact Hx ] ]
      | eapply NegationI; eapply ContradictionI;
        [ eapply ConjunctionE1; apply ByAssumption; simpl; auto
        | eapply extend_infers; [ apply (Hdec1 e) | intros x Hx; unfold E.insert; simpl; right; exact Hx ] ]
      | eapply NegationI; eapply ContradictionI;
        [ eapply ConjunctionE2; apply ByAssumption; simpl; auto
        | eapply extend_infers; [ apply (Hdec2 e) | intros x Hx; unfold E.insert; simpl; right; exact Hx ] ]
      | eapply NegationI; eapply ContradictionI;
        [ eapply ConjunctionE1; apply ByAssumption; simpl; auto
        | eapply extend_infers; [ apply (Hdec1 e) | intros x Hx; unfold E.insert; simpl; right; exact Hx ] ] ]
    | DisjunctionF C1 C2 =>
      destruct IHC1 as [ls1 [Hocc1 Hdec1]]; destruct IHC2 as [ls2 [Hocc2 Hdec2]];
