        [ apply ByAssumption; simpl; auto
        | eapply ContradictionI;
          [ eapply extend_infers; [ apply (Hdec1 e) | intros x Hx; unfold E.insert; simpl; right; right; exact Hx ]
          | apply ByAssumption; simpl; auto ]
        | eapply ContradictionI;
          [ eapply extend_infers; [ apply (Hdec2 e) | intros x Hx; unfold E.insert; simpl; right; right; exact Hx ]
          | apply ByAssumption; simpl; auto ] ] ]
    | ImplicationF C1 C2 =>
      destruct IHC1 as [ls1 [Hocc1 Hdec1]]; destruct IHC2 as [ls2 [Hocc2 Hdec2]];
      intros e; simpl; destruct (eval_bool e C1) eqn:He1; destruct (eval_bool e C2) eqn:He2;
      [ eapply ImplicationI; eapply extend_infers; [ apply (Hdec2 e) | intros x Hx; unfold E.insert; simpl; right; exact Hx ]
      | eapply NegationI; eapply ContradictionI;
        [ eapply ImplicationE;
          [ apply ByAssumption; simpl; auto
          | eapply extend_infers; [ apply (Hdec1 e) | intros x Hx; unfold E.insert; simpl; right; exact Hx ] ]
        | eapply extend_infers; [ apply (Hdec2 e) | intros x Hx; unfold E.insert; simpl; right; exact Hx ] ]
      | eapply ImplicationI; eapply ContradictionE; eapply ContradictionI;
        [ eapply extend_infers; [ apply (Hdec1 e) | intros x Hx; unfold E.insert; simpl; right; exact Hx ]
        | apply ByAssumption; simpl; auto ]
      | eapply ImplicationI; eapply extend_infers; [ apply (Hdec2 e) | intros x Hx; unfold E.insert; simpl; right; exact Hx ] ]
    | BiconditionalF C1 C2 =>
